/**
 * Resource Tracker — self-contained ES module for tracking encounter state.
 * Exports a single `initResourceTracker(statblock, targetElement, instanceNumber)` function.
 *
 * Feature: resource-tracker
 */

// ---------------------------------------------------------------------------
// Spell slot table — standard 5e slots indexed by class (lowercase), then
// by level (1-based index), returning an array of slot counts per spell level.
// ---------------------------------------------------------------------------
const SPELL_SLOTS = {
  // Full casters
  bard:     [ [2],[3],[4,2],[4,3],[4,3,2],[4,3,3],[4,3,3,1],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2,1],[4,3,3,3,2,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1,1],[4,3,3,3,3,1,1,1,1],[4,3,3,3,3,2,1,1,1],[4,3,3,3,3,2,2,1,1] ],
  cleric:   [ [2],[3],[4,2],[4,3],[4,3,2],[4,3,3],[4,3,3,1],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2,1],[4,3,3,3,2,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1,1],[4,3,3,3,3,1,1,1,1],[4,3,3,3,3,2,1,1,1],[4,3,3,3,3,2,2,1,1] ],
  druid:    [ [2],[3],[4,2],[4,3],[4,3,2],[4,3,3],[4,3,3,1],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2,1],[4,3,3,3,2,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1,1],[4,3,3,3,3,1,1,1,1],[4,3,3,3,3,2,1,1,1],[4,3,3,3,3,2,2,1,1] ],
  sorcerer: [ [2],[3],[4,2],[4,3],[4,3,2],[4,3,3],[4,3,3,1],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2,1],[4,3,3,3,2,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1,1],[4,3,3,3,3,1,1,1,1],[4,3,3,3,3,2,1,1,1],[4,3,3,3,3,2,2,1,1] ],
  wizard:   [ [2],[3],[4,2],[4,3],[4,3,2],[4,3,3],[4,3,3,1],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2,1],[4,3,3,3,2,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1],[4,3,3,3,2,1,1,1,1],[4,3,3,3,3,1,1,1,1],[4,3,3,3,3,2,1,1,1],[4,3,3,3,3,2,2,1,1] ],
  // Half casters (slots start at level 2; level 1 row is empty)
  paladin:  [ [],[2],[3],[3],[4,2],[4,2],[4,3],[4,3],[4,3,2],[4,3,2],[4,3,3],[4,3,3],[4,3,3,1],[4,3,3,1],[4,3,3,2],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2] ],
  ranger:   [ [],[2],[3],[3],[4,2],[4,2],[4,3],[4,3],[4,3,2],[4,3,2],[4,3,3],[4,3,3],[4,3,3,1],[4,3,3,1],[4,3,3,2],[4,3,3,2],[4,3,3,3,1],[4,3,3,3,1],[4,3,3,3,2],[4,3,3,3,2] ],
  // Warlock — short-rest pact slots only
  warlock:  [ [1],[2],[0,2],[0,2],[0,0,2],[0,0,2],[0,0,0,2],[0,0,0,2],[0,0,0,0,2],[0,0,0,0,2],[0,0,0,0,3],[0,0,0,0,3],[0,0,0,0,3],[0,0,0,0,3],[0,0,0,0,3],[0,0,0,0,3],[0,0,0,0,4],[0,0,0,0,4],[0,0,0,0,4],[0,0,0,0,4] ],
};

// All standard 5e conditions (exhaustion is tracked separately as a number)
const ALL_CONDITIONS = [
  'blinded', 'charmed', 'frightened', 'grappled',
  'paralyzed', 'petrified', 'poisoned', 'prone',
  'restrained', 'unconscious',
];

// Hit die size per size index (mirrors toolkit5e/packages/base/src/data.ts)
const HIT_DIE_BY_SIZE = { 1: 4, 2: 6, 3: 8, 4: 10, 5: 12, 6: 20 };

// ---------------------------------------------------------------------------
// averageRoll — mirrors the toolkit5e utility (floor of diceCount * (1+dieSize)/2)
// ---------------------------------------------------------------------------
function averageRoll(diceCount, dieSize) {
  return Math.floor(diceCount * ((1 + dieSize) / 2));
}

// ---------------------------------------------------------------------------
// extractResources(statblock, instanceNumber) → ResourceState
// Pure function — no DOM or localStorage side effects.
// ---------------------------------------------------------------------------
export function extractResources(statblock, instanceNumber) {
  const rechargeAbilities = [];
  const restAbilities = [];
  const limitedUseAbilities = [];

  // Keys to skip during the trait scan (to avoid double-counting)
  const skipSet = new Set();

  // --- Legendary Resistance special case ---
  if (statblock.legendaryResistances && statblock.legendaryResistances > 0) {
    limitedUseAbilities.push({
      key: 'legendaryResistance',
      name: 'Legendary Resistance',
      max: statblock.legendaryResistances,
      remaining: statblock.legendaryResistances,
      recharge: 'long',
    });
    skipSet.add('legendaryResistance');
  }

  // --- Scan all four trait collections ---
  const collections = [
    statblock.traits,
    statblock.actions,
    statblock.bonusActions,
    statblock.legendaryActions,
  ];

  const rechargePattern = /\(Recharge (\d)[–\-]6\)/;
  const limitedUsePattern = /(\d+)\/(day|encounter)/i;

  for (const collection of collections) {
    if (!collection) continue;
    for (const key of Object.keys(collection)) {
      if (skipSet.has(key)) continue;
      const trait = collection[key];
      const name = trait.name ?? key;
      const description = trait.description ?? '';

      // 1. Recharge ability (dice-roll recharge)
      const rechargeMatch = rechargePattern.exec(name);
      if (rechargeMatch) {
        rechargeAbilities.push({
          key,
          name,
          threshold: parseInt(rechargeMatch[1], 10),
          available: true,
          lastRoll: null,
        });
      }

      // 2. Rest ability (structured recharge field)
      if (trait.recharge === 'short' || trait.recharge === 'long') {
        restAbilities.push({
          key,
          name,
          restType: trait.recharge,
          available: true,
        });
      }

      // 3. Limited-use ability (N/day or N/encounter in description)
      const limitedMatch = limitedUsePattern.exec(description);
      if (limitedMatch) {
        limitedUseAbilities.push({
          key,
          name,
          max: parseInt(limitedMatch[1], 10),
          remaining: parseInt(limitedMatch[1], 10),
          recharge: trait.recharge ?? null,
        });
      }

      // 4. Innate spellcasting — extract per-spell use counts from spellList
      if (trait.spellList) {
        for (const [spellKey, spellData] of Object.entries(trait.spellList)) {
          const uses = spellData.uses;
          if (uses > 0) {
            limitedUseAbilities.push({
              key: `spell_${spellKey}`,
              name: spellKey.replace(/([A-Z])/g, ' $1').replace(/^./, s => s.toUpperCase()),
              max: uses,
              remaining: uses,
              recharge: 'long',
            });
          }
          // uses === 0 means at-will — no tracking needed
        }
      }
    }
  }

  // --- Derive maxHp ---
  // Mirrors the statblock renderer: averageRoll(hitDice, hitDieSize) + (conMod * hitDice) + bonusHP
  const hitDice = statblock.hitDice ?? 1;
  const hitDieSize = HIT_DIE_BY_SIZE[statblock.size] ?? 8;
  const conMod = statblock.abilityModifiers?.con ?? 0;

  // Account for hitPointsPerHitDie traits (e.g. Dwarven Toughness)
  let traitHpPerDie = 0;
  if (statblock.traits) {
    for (const key of Object.keys(statblock.traits)) {
      const t = statblock.traits[key];
      if (t.hitPointsPerHitDie) traitHpPerDie += t.hitPointsPerHitDie;
    }
  }

  const bonusHP = (conMod * hitDice) + (traitHpPerDie * hitDice) + (statblock.bonusHP ?? 0);
  const maxHp = Math.max(1, averageRoll(hitDice, hitDieSize) + bonusHP);

  // --- Derive spell slots ---
  const spellSlots = [];
  if (statblock.level && statblock.castingClass) {
    const classKey = (Array.isArray(statblock.castingClass)
      ? statblock.castingClass[0]
      : statblock.castingClass
    ).toLowerCase();
    const levelSlots = SPELL_SLOTS[classKey]?.[statblock.level - 1] ?? [];
    for (let i = 0; i < levelSlots.length; i++) {
      if (levelSlots[i] > 0) {
        spellSlots.push({ level: i + 1, max: levelSlots[i], remaining: levelSlots[i] });
      }
    }
  }

  // --- Initialise conditions ---
  const immuneSet = new Set(
    (statblock.conditionImmunities ?? []).map(c => c.toLowerCase())
  );
  const conditions = {};
  for (const condition of ALL_CONDITIONS) {
    if (!immuneSet.has(condition)) {
      conditions[condition] = false;
    }
  }

  return {
    instanceLabel: instanceNumber > 0 ? `${statblock.name} #${instanceNumber}` : statblock.name,
    maxHp,
    currentHp: maxHp,
    hitDiceMax: hitDice,
    hitDiceRemaining: hitDice,
    reactionAvailable: true,
    rechargeAbilities,
    restAbilities,
    spellSlots,
    limitedUseAbilities,
    conditions,
    exhaustion: 0,
  };
}

// ---------------------------------------------------------------------------
// clampHp / clampExhaustion — exported utility clamps
// ---------------------------------------------------------------------------

export function clampHp(value) {
  return Math.max(0, value);
}

export function clampExhaustion(value) {
  return Math.min(6, Math.max(0, value));
}

// ---------------------------------------------------------------------------
// applyRechargeRoll(ability, roll)
// Mutates the ability object in place. Returns nothing.
// ---------------------------------------------------------------------------

export function applyRechargeRoll(ability, roll) {
  if (roll >= ability.threshold) {
    ability.available = true;
  }
  ability.lastRoll = roll;
}

// ---------------------------------------------------------------------------
// applyRound(state)
// Rolls a virtual d6 for each spent recharge ability and resets the reaction.
// ---------------------------------------------------------------------------

export function applyRound(state) {
  for (const ability of state.rechargeAbilities) {
    if (!ability.available) {
      const roll = Math.ceil(Math.random() * 6);
      applyRechargeRoll(ability, roll);
    }
  }
  state.reactionAvailable = true;
}

// ---------------------------------------------------------------------------
// applyShortRest(state, statblock)
// ---------------------------------------------------------------------------

export function applyShortRest(state, statblock) {
  // Restore short-rest rest abilities
  for (const ability of state.restAbilities) {
    if (ability.restType === 'short') {
      ability.available = true;
    }
  }

  // Restore short-rest limited-use abilities
  for (const ability of state.limitedUseAbilities) {
    if (ability.recharge === 'short') {
      ability.remaining = ability.max;
    }
  }

  // Roll hit dice and add to currentHp — spend one die at a time up to remaining
  const hitDice = statblock.hitDice ?? 1;
  const hitDieSize = HIT_DIE_BY_SIZE[statblock.size] ?? 8;
  const conMod = statblock.abilityModifiers?.con ?? 0;
  const diceToSpend = Math.min(hitDice, state.hitDiceRemaining ?? hitDice);

  let total = 0;
  for (let i = 0; i < diceToSpend; i++) {
    const roll = Math.ceil(Math.random() * hitDieSize);
    total += Math.max(0, roll + conMod);
  }
  state.hitDiceRemaining = Math.max(0, (state.hitDiceRemaining ?? hitDice) - diceToSpend);
  state.currentHp = Math.min(state.maxHp, state.currentHp + total);

  // Warlock: restore all spell slots on short rest
  const castingClass = statblock.castingClass;
  const isWarlock = Array.isArray(castingClass)
    ? castingClass.some(c => c.toLowerCase() === 'warlock')
    : typeof castingClass === 'string' && castingClass.toLowerCase() === 'warlock';

  if (isWarlock) {
    for (const slot of state.spellSlots) {
      slot.remaining = slot.max;
    }
  }
}

// ---------------------------------------------------------------------------
// applyLongRest(state, statblock)
// ---------------------------------------------------------------------------

export function applyLongRest(state, statblock) {
  // Restore HP to max
  state.currentHp = state.maxHp;

  // Restore all rest abilities
  for (const ability of state.restAbilities) {
    ability.available = true;
  }

  // Restore all spell slots
  for (const slot of state.spellSlots) {
    slot.remaining = slot.max;
  }

  // Restore all limited-use abilities
  for (const ability of state.limitedUseAbilities) {
    ability.remaining = ability.max;
  }

  // Clear all boolean conditions
  for (const key of Object.keys(state.conditions)) {
    state.conditions[key] = false;
  }

  // Reduce exhaustion by 1, minimum 0
  state.exhaustion = Math.max(0, state.exhaustion - 1);

  // Recover half hit dice (rounded up), per 5e rules
  const maxHitDice = state.hitDiceMax ?? 1;
  state.hitDiceRemaining = Math.min(maxHitDice, (state.hitDiceRemaining ?? 0) + Math.ceil(maxHitDice / 2));

  // Reset reaction
  state.reactionAvailable = true;
}

// ---------------------------------------------------------------------------
// buildStorageKey(slug, cr, instanceNumber)
// Returns the localStorage key for a given monster instance.
// ---------------------------------------------------------------------------

export function buildStorageKey(slug, cr, instanceNumber) {
  const normSlug = slug.toLowerCase().replace(/\s+/g, '-');
  const normCr = String(cr).toLowerCase().replace(/\s+/g, '-');
  return `rt-state-${normSlug}-${normCr}-${instanceNumber}`;
}

// ---------------------------------------------------------------------------
// saveState(key, state)
// Serialises state to localStorage.
// ---------------------------------------------------------------------------

export function saveState(key, state) {
  localStorage.setItem(key, JSON.stringify(state));
}

// ---------------------------------------------------------------------------
// loadState(key, defaultState)
// Deserialises state from localStorage; returns defaultState on failure.
// ---------------------------------------------------------------------------

export function loadState(key, defaultState) {
  try {
    const parsed = JSON.parse(localStorage.getItem(key));
    return parsed ?? defaultState;
  } catch {
    return defaultState;
  }
}

// ---------------------------------------------------------------------------
// clearInstanceKeys(slug, cr)
// Removes all localStorage keys matching rt-state-{slug}-{cr}-*
// ---------------------------------------------------------------------------

export function clearInstanceKeys(slug, cr) {
  const normSlug = slug.toLowerCase().replace(/\s+/g, '-');
  const normCr = String(cr).toLowerCase().replace(/\s+/g, '-');
  const prefix = `rt-state-${normSlug}-${normCr}-`;
  const toRemove = [];
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (k && k.startsWith(prefix)) {
      toRemove.push(k);
    }
  }
  for (const k of toRemove) {
    localStorage.removeItem(k);
  }
}

// ---------------------------------------------------------------------------
// ordinal(n) — returns "1st", "2nd", "3rd", "4th" … "9th"
// ---------------------------------------------------------------------------
function ordinal(n) {
  if (n === 1) return '1st';
  if (n === 2) return '2nd';
  if (n === 3) return '3rd';
  return `${n}th`;
}

// ---------------------------------------------------------------------------
// renderTracker(state, statblock, el)
// Clears el and rebuilds the full tracker DOM from state.
// ---------------------------------------------------------------------------
export function renderTracker(state, statblock, el) {
  // Clear existing content
  while (el.firstChild) el.removeChild(el.firstChild);

  // 1. Header
  const header = document.createElement('div');
  header.className = 'rt-header';
  const instanceLabel = document.createElement('span');
  instanceLabel.className = 'rt-instance-label';
  instanceLabel.textContent = state.instanceLabel;
  header.appendChild(instanceLabel);
  el.appendChild(header);

  // 3. HP section
  const hpSection = document.createElement('div');
  hpSection.className = 'rt-section rt-hp';
  const hpLabel = document.createElement('label');
  hpLabel.textContent = 'Hit Points';
  hpSection.appendChild(hpLabel);

  const hpDisplay = document.createElement('div');
  let hpDisplayClass = 'rt-hp-display';
  if (state.currentHp === 0) hpDisplayClass += ' rt-hp--zero';
  if (state.currentHp > state.maxHp) hpDisplayClass += ' rt-hp--over';
  hpDisplay.className = hpDisplayClass;

  const hpDec = document.createElement('button');
  hpDec.className = 'rt-hp-dec';
  hpDec.textContent = '−';
  hpDisplay.appendChild(hpDec);

  const hpInput = document.createElement('input');
  hpInput.type = 'number';
  hpInput.className = 'rt-hp-input';
  hpInput.min = '0';
  hpInput.value = String(state.currentHp);
  hpDisplay.appendChild(hpInput);

  const hpSep = document.createElement('span');
  hpSep.className = 'rt-hp-sep';
  hpSep.textContent = '/';
  hpDisplay.appendChild(hpSep);

  const hpMax = document.createElement('span');
  hpMax.className = 'rt-hp-max';
  hpMax.textContent = String(state.maxHp);
  hpDisplay.appendChild(hpMax);

  const hpInc = document.createElement('button');
  hpInc.className = 'rt-hp-inc';
  hpInc.textContent = '+';
  hpDisplay.appendChild(hpInc);

  hpSection.appendChild(hpDisplay);

  // Hit dice remaining
  const hdDisplay = document.createElement('div');
  hdDisplay.className = 'rt-hit-dice';
  const hitDieSize = HIT_DIE_BY_SIZE[statblock.size] ?? 8;
  hdDisplay.textContent = `Hit Dice: ${state.hitDiceRemaining ?? state.hitDiceMax}/${state.hitDiceMax} (d${hitDieSize})`;
  hpSection.appendChild(hdDisplay);

  el.appendChild(hpSection);

  // 4. Reaction toggle (always rendered)
  const reactionSection = document.createElement('div');
  reactionSection.className = 'rt-section rt-reaction';
  const reactionBtn = document.createElement('button');
  const reactionAvailable = state.reactionAvailable;
  reactionBtn.className = 'rt-reaction-toggle ' + (reactionAvailable ? 'rt-toggle--available' : 'rt-toggle--spent');
  reactionBtn.setAttribute('aria-pressed', String(!reactionAvailable));
  reactionBtn.textContent = 'Reaction';
  reactionSection.appendChild(reactionBtn);
  el.appendChild(reactionSection);

  // 5. Recharge abilities section (skip if empty)
  if (state.rechargeAbilities && state.rechargeAbilities.length > 0) {
    const rechargeSection = document.createElement('div');
    rechargeSection.className = 'rt-section rt-recharge-abilities';
    const rechargeH4 = document.createElement('h4');
    rechargeH4.textContent = 'Recharge Abilities';
    rechargeSection.appendChild(rechargeH4);

    for (const ability of state.rechargeAbilities) {
      const row = document.createElement('div');
      row.className = 'rt-row';
      row.dataset.key = ability.key;

      const toggleBtn = document.createElement('button');
      toggleBtn.className = 'rt-toggle ' + (ability.available ? 'rt-toggle--available' : 'rt-toggle--spent');
      toggleBtn.setAttribute('aria-pressed', String(!ability.available));
      toggleBtn.textContent = ability.name;
      row.appendChild(toggleBtn);

      const lastRoll = document.createElement('span');
      lastRoll.className = 'rt-last-roll';
      lastRoll.textContent = ability.lastRoll !== null ? 'Rolled: ' + ability.lastRoll : '';
      row.appendChild(lastRoll);

      rechargeSection.appendChild(row);
    }
    el.appendChild(rechargeSection);
  }

  // 6. Rest abilities section (skip if empty)
  if (state.restAbilities && state.restAbilities.length > 0) {
    const restSection = document.createElement('div');
    restSection.className = 'rt-section rt-rest-abilities';
    const restH4 = document.createElement('h4');
    restH4.textContent = 'Rest Abilities';
    restSection.appendChild(restH4);

    for (const ability of state.restAbilities) {
      const row = document.createElement('div');
      row.className = 'rt-row';
      row.dataset.key = ability.key;

      const toggleBtn = document.createElement('button');
      toggleBtn.className = 'rt-toggle ' + (ability.available ? 'rt-toggle--available' : 'rt-toggle--spent');
      toggleBtn.setAttribute('aria-pressed', String(!ability.available));
      toggleBtn.textContent = ability.name;
      row.appendChild(toggleBtn);

      const restType = document.createElement('span');
      restType.className = 'rt-rest-type';
      restType.textContent = ability.restType === 'short' ? 'Short Rest' : 'Long Rest';
      row.appendChild(restType);

      restSection.appendChild(row);
    }
    el.appendChild(restSection);
  }

  // 7. Spell slots section (skip if empty)
  if (state.spellSlots && state.spellSlots.length > 0) {
    const slotsSection = document.createElement('div');
    slotsSection.className = 'rt-section rt-spell-slots';
    const slotsH4 = document.createElement('h4');
    slotsH4.textContent = 'Spell Slots';
    slotsSection.appendChild(slotsH4);

    for (const slot of state.spellSlots) {
      const row = document.createElement('div');
      row.className = 'rt-row';

      const slotLabel = document.createElement('span');
      slotLabel.className = 'rt-slot-label';
      slotLabel.textContent = ordinal(slot.level) + ' level';

      const checkboxes = document.createElement('div');
      checkboxes.className = 'rt-checkboxes';
      for (let i = 0; i < slot.max; i++) {
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.className = 'rt-slot-checkbox';
        cb.dataset.level = String(slot.level);
        cb.dataset.index = String(i);
        if (i >= slot.remaining) cb.checked = true;
        checkboxes.appendChild(cb);
      }
      row.appendChild(checkboxes);
      row.appendChild(slotLabel);
      slotsSection.appendChild(row);
    }
    el.appendChild(slotsSection);
  }

  // 8. Limited-use abilities section (skip if empty)
  if (state.limitedUseAbilities && state.limitedUseAbilities.length > 0) {
    const limitedSection = document.createElement('div');
    limitedSection.className = 'rt-section rt-limited-use';
    const limitedH4 = document.createElement('h4');
    limitedH4.textContent = 'Limited Use';
    limitedSection.appendChild(limitedH4);

    for (const ability of state.limitedUseAbilities) {
      const row = document.createElement('div');
      row.className = 'rt-row';
      row.dataset.key = ability.key;

      const abilityName = document.createElement('span');
      abilityName.className = 'rt-ability-name';
      abilityName.textContent = `${ability.name} (${ability.max}/day)`;

      const checkboxes = document.createElement('div');
      checkboxes.className = 'rt-checkboxes';
      for (let i = 0; i < ability.max; i++) {
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.className = 'rt-use-checkbox';
        cb.dataset.key = ability.key;
        cb.dataset.index = String(i);
        if (i >= ability.remaining) cb.checked = true;
        checkboxes.appendChild(cb);
      }
      row.appendChild(checkboxes);
      row.appendChild(abilityName);
      limitedSection.appendChild(row);
    }
    el.appendChild(limitedSection);
  }

  // 9. Conditions section (always rendered)
  const conditionsSection = document.createElement('div');
  conditionsSection.className = 'rt-section rt-conditions';
  const conditionsH4 = document.createElement('h4');
  conditionsH4.textContent = 'Conditions';
  conditionsSection.appendChild(conditionsH4);

  const conditionGrid = document.createElement('div');
  conditionGrid.className = 'rt-condition-grid';
  for (const [condition, active] of Object.entries(state.conditions)) {
    const btn = document.createElement('button');
    btn.className = 'rt-condition' + (active ? ' rt-condition--active' : '');
    btn.dataset.condition = condition;
    btn.setAttribute('aria-pressed', String(active));
    btn.textContent = condition.charAt(0).toUpperCase() + condition.slice(1);
    conditionGrid.appendChild(btn);
  }
  conditionsSection.appendChild(conditionGrid);

  const exhaustionDiv = document.createElement('div');
  exhaustionDiv.className = 'rt-exhaustion';
  const exhaustionLabel = document.createElement('label');
  exhaustionLabel.textContent = 'Exhaustion';
  exhaustionDiv.appendChild(exhaustionLabel);

  const exhaustionDec = document.createElement('button');
  exhaustionDec.className = 'rt-exhaustion-dec';
  exhaustionDec.textContent = '−';
  exhaustionDiv.appendChild(exhaustionDec);

  const exhaustionInput = document.createElement('input');
  exhaustionInput.type = 'number';
  exhaustionInput.className = 'rt-exhaustion-input';
  exhaustionInput.min = '0';
  exhaustionInput.max = '6';
  exhaustionInput.value = String(state.exhaustion);
  exhaustionDiv.appendChild(exhaustionInput);

  const exhaustionInc = document.createElement('button');
  exhaustionInc.className = 'rt-exhaustion-inc';
  exhaustionInc.textContent = '+';
  exhaustionDiv.appendChild(exhaustionInc);

  conditionsSection.appendChild(exhaustionDiv);
  el.appendChild(conditionsSection);
}

// ---------------------------------------------------------------------------
// bindEvents(state, statblock, el, saveDebounced)
// Attaches all event listeners via delegation on el.
// ---------------------------------------------------------------------------
export function bindEvents(state, statblock, el, saveDebounced) {
  el.addEventListener('click', (e) => {
    const target = e.target;

    // HP dec
    if (target.classList.contains('rt-hp-dec')) {
      state.currentHp = clampHp(state.currentHp - 1);
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // HP inc (no upper clamp — over-max is valid)
    if (target.classList.contains('rt-hp-inc')) {
      state.currentHp = state.currentHp + 1;
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Reaction toggle
    if (target.classList.contains('rt-reaction-toggle')) {
      state.reactionAvailable = !state.reactionAvailable;
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Recharge ability toggle
    if (target.classList.contains('rt-toggle')) {
      const row = target.closest('.rt-row');
      if (!row) return;
      const key = row.dataset.key;

      // Check which section this toggle is in
      const section = target.closest('.rt-recharge-abilities, .rt-rest-abilities');
      if (!section) return;

      if (section.classList.contains('rt-recharge-abilities')) {
        const ability = state.rechargeAbilities.find(a => a.key === key);
        if (ability) ability.available = !ability.available;
      } else if (section.classList.contains('rt-rest-abilities')) {
        const ability = state.restAbilities.find(a => a.key === key);
        if (ability) ability.available = !ability.available;
      }

      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Condition toggle
    if (target.classList.contains('rt-condition')) {
      const condition = target.dataset.condition;
      if (condition in state.conditions) {
        state.conditions[condition] = !state.conditions[condition];
      }
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Exhaustion dec
    if (target.classList.contains('rt-exhaustion-dec')) {
      state.exhaustion = clampExhaustion(state.exhaustion - 1);
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Exhaustion inc
    if (target.classList.contains('rt-exhaustion-inc')) {
      state.exhaustion = clampExhaustion(state.exhaustion + 1);
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }
  });

  el.addEventListener('change', (e) => {
    const target = e.target;

    // HP input
    if (target.classList.contains('rt-hp-input')) {
      state.currentHp = clampHp(parseInt(target.value, 10) || 0);
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }

    // Spell slot checkbox
    if (target.classList.contains('rt-slot-checkbox')) {
      const level = parseInt(target.dataset.level, 10);
      const slot = state.spellSlots.find(s => s.level === level);
      if (slot) {
        // Count unchecked boxes for this level
        const checkboxes = el.querySelectorAll(`.rt-slot-checkbox[data-level="${level}"]`);
        let unchecked = 0;
        for (const cb of checkboxes) {
          if (!cb.checked) unchecked++;
        }
        slot.remaining = unchecked;
      }
      saveDebounced();
      return;
    }

    // Limited-use checkbox
    if (target.classList.contains('rt-use-checkbox')) {
      const key = target.dataset.key;
      const ability = state.limitedUseAbilities.find(a => a.key === key);
      if (ability) {
        const checkboxes = el.querySelectorAll(`.rt-use-checkbox[data-key="${key}"]`);
        let unchecked = 0;
        for (const cb of checkboxes) {
          if (!cb.checked) unchecked++;
        }
        ability.remaining = unchecked;
      }
      saveDebounced();
      return;
    }

    // Exhaustion input
    if (target.classList.contains('rt-exhaustion-input')) {
      state.exhaustion = clampExhaustion(parseInt(target.value, 10) || 0);
      renderTracker(state, statblock, el);
      saveDebounced();
      return;
    }
  });
}

// ---------------------------------------------------------------------------
// initResourceTracker(statblock, targetElement, instanceNumber)
// Public API — initialises the tracker, renders it, and returns a controller.
// ---------------------------------------------------------------------------
export function initResourceTracker(statblock, targetElement, instanceNumber) {
  // 1. Extract initial state
  const defaultState = extractResources(statblock, instanceNumber);

  // 2. Build storage key and try to restore from localStorage
  const storageKey = buildStorageKey(statblock.slug ?? statblock.name, statblock.cr ?? '0', instanceNumber);
  let state = loadState(storageKey, defaultState);

  // 3. Render initial UI
  renderTracker(state, statblock, targetElement);

  // 4. Create debounced save (500ms)
  let saveTimer = null;
  function saveDebounced() {
    clearTimeout(saveTimer);
    saveTimer = setTimeout(() => saveState(storageKey, state), 500);
  }

  // 5. Bind events
  bindEvents(state, statblock, targetElement, saveDebounced);

  // 6. Return controller object
  return {
    applyRound() {
      applyRound(state);
      renderTracker(state, statblock, targetElement);
      saveState(storageKey, state);
    },
    applyShortRest() {
      applyShortRest(state, statblock);
      renderTracker(state, statblock, targetElement);
      saveState(storageKey, state);
    },
    applyLongRest() {
      applyLongRest(state, statblock);
      renderTracker(state, statblock, targetElement);
      saveState(storageKey, state);
    },
  };
}
